  if (!pathFn) return null;
  const isMultiColor = pathFn.length === 0;
  const html = isMultiColor ? pathFn() : pathFn(c);
  const multiColorScale = (isMultiColor && id && id.startsWith("i_lend_")) ? 2.2 : 1.4;
  const renderSize = isMultiColor ? Math.round((size || 20) * multiColorScale) : (size || 20);
  if (isMultiColor) {
    return <svg width={renderSize} height={renderSize} viewBox="0 0 36 36" xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink" dangerouslySetInnerHTML={{__html: html}} />;
  }
  return <svg width={renderSize} height={renderSize} viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg" dangerouslySetInnerHTML={{__html: html}} />;
