  const lv = level || 0;
  const els = [];
  // viewBox 100x100, center 50,50. Main ring r=38
  // Estrutura principal: cor do tema (c)
  els.push(`<circle cx="50" cy="50" r="38" stroke="${c}" stroke-width="3.5" fill="none"/>`);
  if (lv >= 2) els.push(`<circle cx="50" cy="50" r="43" stroke="${c}" stroke-width="1.5" opacity="0.5" fill="none"/>`);
  // N/S cardinais: cor do tema
  if (lv >= 3) { els.push(`<circle cx="50" cy="4" r="2.5" fill="${c}" opacity="0.75"/>`); els.push(`<circle cx="50" cy="96" r="2.5" fill="${c}" opacity="0.75"/>`); }
  // E/W cardinais: cor accent (primeira aparição do material)
  if (lv >= 4) { els.push(`<circle cx="4" cy="50" r="2.5" fill="${ac}" opacity="0.75"/>`); els.push(`<circle cx="96" cy="50" r="2.5" fill="${ac}" opacity="0.75"/>`); }
  // Pontos de canto: accent
  if (lv >= 5) { els.push(`<circle cx="17" cy="17" r="2" fill="${ac}" opacity="0.65"/><circle cx="83" cy="17" r="2" fill="${ac}" opacity="0.65"/><circle cx="17" cy="83" r="2" fill="${ac}" opacity="0.65"/><circle cx="83" cy="83" r="2" fill="${ac}" opacity="0.65"/>`); }
  // Setas cardinais: N/S tema, E/W accent
