  // Anel mais externo: tema; 8 marcadores de borda: accent
  if (lv >= 9) { els.push(`<circle cx="50" cy="50" r="47" stroke="${c}" stroke-width="1" opacity="0.25" fill="none"/>`); els.push(`<path d="M30 3L33 7L30 6L27 7Z" fill="${ac}" opacity="0.55"/><path d="M70 3L73 7L70 6L67 7Z" fill="${ac}" opacity="0.55"/><path d="M30 97L33 93L30 94L27 93Z" fill="${ac}" opacity="0.55"/><path d="M70 97L73 93L70 94L67 93Z" fill="${ac}" opacity="0.55"/><path d="M3 30L7 33L6 30L7 27Z" fill="${ac}" opacity="0.55"/><path d="M97 30L93 33L94 30L93 27Z" fill="${ac}" opacity="0.55"/><path d="M3 70L7 67L6 70L7 73Z" fill="${ac}" opacity="0.55"/><path d="M97 70L93 67L94 70L93 73Z" fill="${ac}" opacity="0.55"/>`); }
  // Filigrana de arco: accent (o clímax visual); diamantes dos eixos: tema
  if (lv >= 10) { els.push(`<path d="M50 1 A49 49 0 0 1 67 4" stroke="${ac}" stroke-width="2.2" stroke-linecap="round" opacity="0.55" fill="none"/><path d="M99 50 A49 49 0 0 1 96 67" stroke="${ac}" stroke-width="2.2" stroke-linecap="round" opacity="0.55" fill="none"/><path d="M50 99 A49 49 0 0 1 33 96" stroke="${ac}" stroke-width="2.2" stroke-linecap="round" opacity="0.55" fill="none"/><path d="M1 50 A49 49 0 0 1 4 33" stroke="${ac}" stroke-width="2.2" stroke-linecap="round" opacity="0.55" fill="none"/>`); els.push(`<path d="M50 0L52 3L50 2L48 3Z" fill="${c}" opacity="0.6"/><path d="M100 50L97 52L98 50L97 48Z" fill="${c}" opacity="0.6"/><path d="M50 100L48 97L50 98L52 97Z" fill="${c}" opacity="0.6"/><path d="M0 50L3 48L2 50L3 52Z" fill="${c}" opacity="0.6"/>`); }
