const UPGRADE_COSTS = [30, 50, 80, 120, 170, 230, 300, 400, 500, 650];
const MAX_UPGRADE = 10;
function getUpgradeCost(level) { return UPGRADE_COSTS[level] || null; }
function getTitleStyle(level) {
  return { fontWeight: 600 };
}
function lerpColor(a, b, t) {
  const ah = parseInt(a.slice(1), 16), bh = parseInt(b.slice(1), 16);
  const ar = (ah >> 16) & 0xff, ag = (ah >> 8) & 0xff, ab = ah & 0xff;
  const br = (bh >> 16) & 0xff, bg = (bh >> 8) & 0xff, bb2 = bh & 0xff;
  const r = Math.round(ar + (br - ar) * t);
  const g = Math.round(ag + (bg - ag) * t);
  const b2 = Math.round(ab + (bb2 - ab) * t);
  return "#" + ((r << 16) | (g << 8) | b2).toString(16).padStart(6, "0");
}
function getTitleTargetColor(price) {
  if (!price || price <= 0) return null;
  if (price <= 10)  return "#8888bb";
  if (price <= 30)  return "#b08858";
  if (price <= 80)  return "#cd7f32";
  if (price <= 120) return "#c0c8d8";
  if (price <= 200) return "#d4af37";
  if (price <= 300) return "#f0d040";
  if (price <= 400) return "#44ccff";
  return "#dd44ff";
}
function getTitleBannerColor() { return C.gold; }
function getBorderStyle(borderObj, level) {
  const color = (borderObj && borderObj.color) || "#444";
  if (level <= 0) return { border: "2px solid " + color };
  const w = level <= 3 ? (2 + level) : level <= 6 ? (5 + Math.floor(level/2)) : (6 + Math.floor(level/2));
  const glow = level <= 3 ? "none" : level <= 6 ? "0 0 " + (level*2) + "px " + color + "50" : "0 0 " + (level*3) + "px " + color + "80";
  return { border: w + "px solid " + color, boxShadow: glow };
}
